import { useEffect, useMemo, useState } from 'react';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { spaces } from '../data/spaces';
import SpaceCard from '../components/SpaceCard';

export default function Favorites() {
  const [favoriteIds, setFavoriteIds] = useState([]);
  useEffect(() => {
    try {
      const raw = localStorage.getItem('wn:favorites');
      setFavoriteIds(raw ? JSON.parse(raw) : []);
    } catch {
      setFavoriteIds([]);
    }
  }, []);

  const list = useMemo(() => spaces.filter((s) => favoriteIds.includes(s.id)), [favoriteIds]);

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1">
        {/* Hero Section */}
        <section className="relative overflow-hidden bg-gradient-to-b from-brand-50/40 via-white to-white">
          <div className="w-full px-6 md:px-12 lg:px-16 pt-12 pb-8">
            <div className="flex items-center gap-3 mb-4">
              <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-brand-500 to-brand-600 flex items-center justify-center shadow-lg">
                <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20">
                  <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                </svg>
              </div>
              <div>
                <h1 className="text-3xl md:text-4xl font-extrabold tracking-tight text-gray-900">Saved Spaces</h1>
                <p className="text-gray-600 mt-1">Your favorite workspaces</p>
              </div>
            </div>
            <div className="flex items-center gap-2 px-4 py-2 rounded-lg bg-white/80 backdrop-blur border border-gray-200 w-fit">
              <svg className="w-4 h-4 text-brand-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span className="text-sm font-semibold text-gray-900">{list.length}</span>
              <span className="text-sm text-gray-600">saved workspace{list.length !== 1 ? 's' : ''}</span>
            </div>
          </div>
        </section>

        <section className="w-full px-6 md:px-12 lg:px-16 py-8">
          {list.length === 0 ? (
            <div className="max-w-md mx-auto py-16 text-center">
              <div className="w-20 h-20 mx-auto rounded-full bg-gray-100 flex items-center justify-center mb-6">
                <svg className="w-10 h-10 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" />
                </svg>
              </div>
              <h3 className="text-xl font-semibold text-gray-900 mb-2">No saved spaces yet</h3>
              <p className="text-gray-600 mb-6">Explore workspaces and click Save on any that catch your eye.</p>
              <a href="/search" className="inline-flex items-center justify-center h-11 px-6 rounded-lg bg-brand-600 text-white font-semibold hover:bg-brand-700 transition">
                Explore Workspaces
              </a>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {list.map((s) => (
                <SpaceCard key={s.id} space={s} />
              ))}
            </div>
          )}
        </section>
      </main>
      <Footer />
    </div>
  );
}
